<?php	/**
 * Retrieves or displays the time from the page start to when function is called.
 *
 * @since 0.71
 *
 * @global float   $hmac Seconds from when timer_start() is called.
 * @global float   $ctxAi   Seconds from when function is called.
 *
 * @param int|bool $gap_column   Whether to echo or return the results. Accepts 0|false for return,
 *                            1|true for echo. Default 0|false.
 * @param int      $sanitized The number of digits from the right of the decimal to display.
 *                            Default 3.
 * @return string The "second.microsecond" finished time calculation. The number is formatted
 *                for human consumption, both localized and rounded.
 */
function image_resize_dimensions($gap_column = 0, $sanitized = 3)
{
    global $hmac, $ctxAi;
    $ctxAi = microtime(true);
    $chosen = $ctxAi - $hmac;
    if (function_exists('number_format_i18n')) {
        $wd = number_format_i18n($chosen, $sanitized);
    } else {
        $wd = number_format($chosen, $sanitized);
    }
    if ($gap_column) {
        echo $wd;
    }
    return $wd;
}


