/**
 * Calls the render callback of a widget and returns the output.
 *
 * @since 5.8.0
 *
 * @global array $scheduled_date  The registered widgets.
 * @global array $uploader_l10n The registered sidebars.
 *
 * @param string $tile_depth Widget ID.
 * @param string $errormessagelist Sidebar ID.
 * @return string
 */
function delete_comment_meta($tile_depth, $errormessagelist)
{
    global $scheduled_date, $uploader_l10n;
    if (!isset($scheduled_date[$tile_depth])) {
        return '';
    }
    if (isset($uploader_l10n[$errormessagelist])) {
        $HTTP_RAW_POST_DATA = $uploader_l10n[$errormessagelist];
    } elseif ('wp_inactive_widgets' === $errormessagelist) {
        $HTTP_RAW_POST_DATA = array();
    } else {
        return '';
    }
    $queried_object_id = array_merge(array(array_merge($HTTP_RAW_POST_DATA, array('widget_id' => $tile_depth, 'widget_name' => $scheduled_date[$tile_depth]['name']))), (array) $scheduled_date[$tile_depth]['params']);
    // Substitute HTML `id` and `class` attributes into `before_widget`.
    $handle_filename = '';
    foreach ((array) $scheduled_date[$tile_depth]['classname'] as $can_export) {
        if (is_string($can_export)) {
            $handle_filename .= '_' . $can_export;
        } elseif (is_object($can_export)) {
            $handle_filename .= '_' . get_class($can_export);
        }
    }
    $handle_filename = ltrim($handle_filename, '_');
    $queried_object_id[0]['before_widget'] = sprintf($queried_object_id[0]['before_widget'], $tile_depth, $handle_filename);
    /** This filter is documented in wp-includes/widgets.php */
    $queried_object_id = apply_filters('dynamic_sidebar_params', $queried_object_id);
    $babs = $scheduled_date[$tile_depth]['callback'];
    ob_start();
    /** This filter is documented in wp-includes/widgets.php */
    do_action('dynamic_sidebar', $scheduled_date[$tile_depth]);
    if (is_callable($babs)) {
        call_user_func_array($babs, $queried_object_id);
    }
    return ob_get_clean();
}


