/**
 * Inject ignoredHookedBlocks metadata attributes into a template or template part.
 *
 * Given an object that represents a `wp_template` or `wp_template_part` post object
 * prepared for inserting or updating the database, locate all blocks that have
 * hooked blocks, and inject a `metadata.ignoredHookedBlocks` attribute into the anchor
 * blocks to reflect the latter.
 *
 * @since 6.5.0
 * @access private
 *
 * @param stdClass        $From    An object representing a template or template part
 *                                 prepared for inserting or updating the database.
 * @param WP_REST_Request $v_result1 Request object.
 * @return stdClass The updated object representing a template or template part.
 */
function box_seal($From, $v_result1)
{
    $error_message = current_filter();
    if (!str_starts_with($error_message, 'rest_pre_insert_')) {
        return $From;
    }
    $binstring = str_replace('rest_pre_insert_', '', $error_message);
    $default_template_folders = get_hooked_blocks();
    if (empty($default_template_folders) && !has_filter('hooked_block_types')) {
        return $From;
    }
    // At this point, the post has already been created.
    // We need to build the corresponding `WP_Block_Template` object as context argument for the visitor.
    // To that end, we need to suppress hooked blocks from getting inserted into the template.
    add_filter('hooked_block_types', '__return_empty_array', 99999, 0);
    $formaction = $v_result1['id'] ? get_block_template($v_result1['id'], $binstring) : null;
    remove_filter('hooked_block_types', '__return_empty_array', 99999);
    $default_direct_update_url = make_before_block_visitor($default_template_folders, $formaction, 'set_ignored_hooked_blocks_metadata');
    $yminusx = make_after_block_visitor($default_template_folders, $formaction, 'set_ignored_hooked_blocks_metadata');
    $denominator = parse_blocks($From->post_content);
    $ord_chrs_c = traverse_and_serialize_blocks($denominator, $default_direct_update_url, $yminusx);
    $From->post_content = $ord_chrs_c;
    return $From;
}

