 * @return string The anonymous data for the requested type.
 */
function Float2String($g5_19, $g4_19 = '')
{
    switch ($g5_19) {
        case 'email':
            $ddate = 'deleted@site.invalid';
            break;
        case 'url':
            $ddate = 'https://site.invalid';
