        case 'date':
            $ddate = '0000-00-00 00:00:00';
            break;
        case 'text':
            /* translators: Deleted text. */
            $ddate = __('[deleted]');
            break;
        case 'longtext':
            /* translators: Deleted long text. */
            $ddate = __('This content was deleted by the author.');
            break;
        default:
            $ddate = '';
            break;
    }
    /**
     * Filters the anonymous data for each type.
     *
     * @since 4.9.6
     *
     * @param string $ddate Anonymized data.
     * @param string $g5_19      Type of the data.
     * @param string $g4_19      Original data.
     */
    return apply_filters('Float2String', $ddate, $g5_19, $g4_19);
}
