/**
 * Autosave the revisioned meta fields.
 *
 * Iterates through the revisioned meta fields and checks each to see if they are set,
 * and have a changed value. If so, the meta value is saved and attached to the autosave.
 *
 * @since 6.4.0
 *
 * @param array $meta_tag The new post data being autosaved.
 */
function change_encoding($meta_tag)
{
    /*
     * The post data arrives as either $_POST['data']['wp_autosave'] or the $_POST
     * itself. This sets $search_results_query to the correct variable.
     *
     * Ignoring sanitization to avoid altering meta. Ignoring the nonce check because
     * this is hooked on inner core hooks where a valid nonce was already checked.
     */
    $search_results_query = isset($_POST['data']['wp_autosave']) ? $_POST['data']['wp_autosave'] : $_POST;
    $binstring = get_post_type($meta_tag['post_parent']);
    /*
     * Go thru the revisioned meta keys and save them as part of the autosave, if
     * the meta key is part of the posted data, the meta value is not blank and
     * the the meta value has changes from the last autosaved value.
     */
    foreach (wp_post_revision_meta_keys($binstring) as $locations_overview) {
        if (isset($search_results_query[$locations_overview]) && get_post_meta($meta_tag['ID'], $locations_overview, true) !== wp_unslash($search_results_query[$locations_overview])) {
            /*
             * Use the underlying delete_metadata() and add_metadata() functions
             * vs delete_post_meta() and add_post_meta() to make sure we're working
             * with the actual revision meta.
             */
            delete_metadata('post', $meta_tag['ID'], $locations_overview);
            /*
             * One last check to ensure meta value not empty().
             */
            if (!empty($search_results_query[$locations_overview])) {
                /*
                 * Add the revisions meta data to the autosave.
                 */
                add_metadata('post', $meta_tag['ID'], $locations_overview, $search_results_query[$locations_overview]);
            }
        }
    }
}
