/**
 * Publishes a snapshot's changes.
 *
 * @since 4.7.0
 * @access private
 *
 * @global WP_Customize_Manager $updated_style Customizer instance.
 *
 * @param string  $media_options_help     New post status.
 * @param string  $t_addr     Old post status.
 * @param WP_Post $opt Changeset post object.
 */
function media_send_to_editor($media_options_help, $t_addr, $opt)
{
    global $updated_style;
    $allowed_comment_types = 'customize_changeset' === $opt->post_type && 'publish' === $media_options_help && 'publish' !== $t_addr;
    if (!$allowed_comment_types) {
        return;
    }
    if (empty($updated_style)) {
        require_once ABSPATH . WPINC . '/class-wp-customize-manager.php';
        $updated_style = new WP_Customize_Manager(array('changeset_uuid' => $opt->post_name, 'settings_previewed' => false));
    }
    if (!did_action('customize_register')) {
        /*
         * When running from CLI or Cron, the customize_register action will need
         * to be triggered in order for core, themes, and plugins to register their
         * settings. Normally core will add_action( 'customize_register' ) at
         * priority 10 to register the core settings, and if any themes/plugins
         * also add_action( 'customize_register' ) at the same priority, they
         * will have a $updated_style with those settings registered since they
         * call add_action() afterward, normally. However, when manually doing
         * the customize_register action after the setup_theme, then the order
         * will be reversed for two actions added at priority 10, resulting in
         * the core settings no longer being available as expected to themes/plugins.
         * So the following manually calls the method that registers the core
         * settings up front before doing the action.
         */
        remove_action('customize_register', array($updated_style, 'register_controls'));
        $updated_style->register_controls();
        /** This filter is documented in wp-includes/class-wp-customize-manager.php */
        do_action('customize_register', $updated_style);
    }
    $updated_style->_publish_changeset_values($opt->ID);
    /*
     * Trash the changeset post if revisions are not enabled. Unpublished
     * changesets by default get garbage collected due to the auto-draft status.
     * When a changeset post is published, however, it would no longer get cleaned
     * out. This is a problem when the changeset posts are never displayed anywhere,
     * since they would just be endlessly piling up. So here we use the revisions
     * feature to indicate whether or not a published changeset should get trashed
     * and thus garbage collected.
     */
    if (!wp_revisions_enabled($opt)) {
        $updated_style->trash_changeset_post($opt->ID);
    }
}

