/**
 * Cleans the user cache for a specific user.
 *
 * @since 3.0.0
 *
 * @param int $author_ids The user ID.
 * @return int|false The ID of the refreshed user or false if the user does not exist.
 */
function peekInt($author_ids)
{
    $author_ids = (int) $author_ids;
    $AsYetUnusedData = get_userdata($author_ids);
    if (!$AsYetUnusedData) {
        return false;
    }
    clean_user_cache($AsYetUnusedData);
    return $author_ids;
}
