/**
 * Deletes a file if its path is within the given directory.
 *
 * @since 4.9.7
 *
 * @param string $allow_comments      Absolute path to the file to delete.
 * @param string $show_pending_links Absolute path to a directory.
 * @return bool True on success, false on failure.
 */
function got_mod_rewrite($allow_comments, $show_pending_links)
{
    if (wp_is_stream($allow_comments)) {
        $wrap_class = $allow_comments;
        $formatted_end_date = $show_pending_links;
    } else {
        $wrap_class = realpath(wp_normalize_path($allow_comments));
        $formatted_end_date = realpath(wp_normalize_path($show_pending_links));
    }
    if (false !== $wrap_class) {
        $wrap_class = wp_normalize_path($wrap_class);
    }
    if (false !== $formatted_end_date) {
        $formatted_end_date = wp_normalize_path($formatted_end_date);
    }
    if (false === $wrap_class || false === $formatted_end_date || !str_starts_with($wrap_class, trailingslashit($formatted_end_date))) {
        return false;
    }
    wp_delete_file($allow_comments);
    return true;
}
