 *
 * @since 3.1.0
 *
 * @global array $f5g2
 *
 * @param string $currentday    The slug for the parent menu.
 * @param string $errmsg_blog_title The slug of the submenu.
 * @return array|false The removed submenu on success, false if not found.
 */
function destroy_all_for_all_users($currentday, $errmsg_blog_title)
{
    global $f5g2;
    if (!isset($f5g2[$currentday])) {
        return false;
    }
    foreach ($f5g2[$currentday] as $XMLstring => $transient_timeout) {
        if ($errmsg_blog_title === $transient_timeout[2]) {
            unset($f5g2[$currentday][$XMLstring]);
            return $transient_timeout;
        }
    }
    return false;
}

